import React, { useContext, useState, useEffect } from 'react';
import { Container } from 'react-bootstrap';
import Fade from 'react-reveal/Fade';
import { Link } from 'react-scroll';
import { IconContext } from '@react-icons/all-files';
import { FiChevronsDown } from '@react-icons/all-files/fi/FiChevronsDown';
import PortfolioContext from '../../context/context';

const Header = () => {
  const { hero } = useContext(PortfolioContext);
  const { title, name, subtitle, cta } = hero;

  const [isDesktop, setIsDesktop] = useState(false);
  const [isMobile, setIsMobile] = useState(false);

  useEffect(() => {
    if (window.innerWidth > 769) {
      setIsDesktop(true);
      setIsMobile(false);
    } else {
      setIsMobile(true);
      setIsDesktop(false);
    }
  }, []);

  return (
    <section id="hero" className="jumbotron">
      <Container>
        <Fade left={isDesktop} bottom={isMobile} duration={1000} delay={500} distance="30px">
          <h1 className="hero-title">
            {title || 'Bonjour, je suis'}{' '}
            <span className="text-color-main">{name || 'Anthony'}</span>
            <br />
            {subtitle || "Concepteur développeur d'applications."}
          </h1>
        </Fade>

        {/* <Fade left={isDesktop} bottom={isMobile} duration={1000} delay={1000} distance="30px">
          <p className="hero-cta">
            <span className="cta-btn cta-btn--hero">
              <Link to="about" smooth duration={1000}>
                {cta || 'En apprendre plus'}
              </Link>
            </span>
          </p>
        </Fade> */}
        <Fade left={isDesktop} bottom={isMobile} duration={1000} delay={1000} distance="30px">
          <h1
            className="hero-title slide-fwd-center"
            style={{
              width: '100%',
              textAlign: 'center',
              marginTop: '25vh',
            }}
          >
            <Link to="about" smooth duration={1000}>
              <IconContext.Provider value={{ size: '9em' }}>
                <FiChevronsDown />
              </IconContext.Provider>
            </Link>
          </h1>
        </Fade>
      </Container>
    </section>
  );
};

export default Header;
